/**
 * Form Builder Templates Section - Enhanced with Icons & Infographics
 * Author: generated by Amazon Q
 * Created: 2024-12-21
 * Updated: 2025-01-XX - Added infographic support, FA icons, gradient titles, auto-scroll
 */

'use client';

import React, { useRef, useEffect, useState } from 'react';
import InfographicRenderer from './InfographicRenderer';

interface FormBuilderTemplatesProps {
  data: {
    title: string;
    description: string;
    autoScroll?: boolean;
    scrollSpeed?: number; // milliseconds (default: 3000)
    templates: Array<{
      title: string;
      description: string;
      icon?: string;
      infographic?: {
        type: string;
        data: any;
      };
    }>;
  };
  style?: any;
}

export default function FormBuilderTemplatesSection({ data }: FormBuilderTemplatesProps) {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [isPaused, setIsPaused] = useState(false);
  const autoScrollEnabled = data.autoScroll !== false; // default true
  const scrollSpeed = data.scrollSpeed || 3000; // default 3 seconds

  const scroll = (direction: 'left' | 'right') => {
    if (scrollRef.current) {
      const scrollAmount = 400;
      scrollRef.current.scrollBy({
        left: direction === 'left' ? -scrollAmount : scrollAmount,
        behavior: 'smooth'
      });
    }
  };

  // Auto-scroll functionality
  useEffect(() => {
    if (!autoScrollEnabled || isPaused || !scrollRef.current) return;

    const scrollContainer = scrollRef.current;
    const cardWidth = 400 + 24; // card width + gap

    const autoScroll = () => {
      if (!scrollContainer) return;

      const maxScroll = scrollContainer.scrollWidth - scrollContainer.clientWidth;
      const currentScroll = scrollContainer.scrollLeft;

      // If reached end, scroll back to start
      if (currentScroll >= maxScroll - 10) {
        scrollContainer.scrollTo({ left: 0, behavior: 'smooth' });
      } else {
        // Scroll one card width
        scrollContainer.scrollBy({ left: cardWidth, behavior: 'smooth' });
      }
    };

    const interval = setInterval(autoScroll, scrollSpeed);

    return () => clearInterval(interval);
  }, [autoScrollEnabled, isPaused, scrollSpeed]);

  const themeConfigs = [
    {
      gradient: 'from-blue-500 via-cyan-500 to-blue-600',
      bg: 'bg-gradient-to-br from-blue-50/80 to-cyan-50/80 dark:from-blue-950/30 dark:to-cyan-950/30',
      border: 'border-blue-200/50 dark:border-blue-500/20',
      iconBg: 'bg-blue-100 dark:bg-blue-900/40',
      iconText: 'text-blue-600 dark:text-blue-400',
      text: 'text-blue-900 dark:text-blue-100'
    },
    {
      gradient: 'from-emerald-500 via-teal-500 to-emerald-600',
      bg: 'bg-gradient-to-br from-emerald-50/80 to-teal-50/80 dark:from-emerald-950/30 dark:to-teal-950/30',
      border: 'border-emerald-200/50 dark:border-emerald-500/20',
      iconBg: 'bg-emerald-100 dark:bg-emerald-900/40',
      iconText: 'text-emerald-600 dark:text-emerald-400',
      text: 'text-emerald-900 dark:text-emerald-100'
    },
    {
      gradient: 'from-violet-500 via-purple-500 to-violet-600',
      bg: 'bg-gradient-to-br from-violet-50/80 to-purple-50/80 dark:from-violet-950/30 dark:to-purple-950/30',
      border: 'border-violet-200/50 dark:border-violet-500/20',
      iconBg: 'bg-violet-100 dark:bg-violet-900/40',
      iconText: 'text-violet-600 dark:text-violet-400',
      text: 'text-violet-900 dark:text-violet-100'
    },
    {
      gradient: 'from-amber-500 via-orange-500 to-amber-600',
      bg: 'bg-gradient-to-br from-amber-50/80 to-orange-50/80 dark:from-amber-950/30 dark:to-orange-950/30',
      border: 'border-amber-200/50 dark:border-amber-500/20',
      iconBg: 'bg-amber-100 dark:bg-amber-900/40',
      iconText: 'text-amber-600 dark:text-amber-400',
      text: 'text-amber-900 dark:text-amber-100'
    },
    {
      gradient: 'from-rose-500 via-pink-500 to-rose-600',
      bg: 'bg-gradient-to-br from-rose-50/80 to-pink-50/80 dark:from-rose-950/30 dark:to-pink-950/30',
      border: 'border-rose-200/50 dark:border-rose-500/20',
      iconBg: 'bg-rose-100 dark:bg-rose-900/40',
      iconText: 'text-rose-600 dark:text-rose-400',
      text: 'text-rose-900 dark:text-rose-100'
    }
  ];

  return (
    <section className="mx-auto max-w-7xl px-6 py-20 bg-white dark:bg-slate-900">
      <div className="flex items-end justify-between mb-10">
        <div>
          <h2 className="text-4xl md:text-5xl font-bold bg-gradient-to-r from-blue-600 via-violet-600 to-purple-600 dark:from-blue-400 dark:via-violet-400 dark:to-purple-400 bg-clip-text text-transparent">
            {data.title}
          </h2>
          <p className="mt-4 text-lg text-slate-600 dark:text-slate-300 max-w-3xl">{data.description}</p>
        </div>
        <div className="flex gap-2">
          {autoScrollEnabled && (
            <button 
              type="button"
              onClick={() => setIsPaused(!isPaused)}
              className="w-10 h-10 rounded-xl bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-200 transition-all border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md"
              title={isPaused ? 'Resume auto-scroll' : 'Pause auto-scroll'}
            >
              {isPaused ? '▶' : '⏸'}
            </button>
          )}
          <button 
            type="button"
            onClick={() => scroll('left')}
            className="w-10 h-10 rounded-xl bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-200 transition-all border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md"
          >
            ‹
          </button>
          <button 
            type="button"
            onClick={() => scroll('right')}
            className="w-10 h-10 rounded-xl bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-200 transition-all border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md"
          >
            ›
          </button>
        </div>
      </div>
      
      <div 
        ref={scrollRef}
        className="overflow-x-auto scrollbar-thin scrollbar-thumb-slate-300 dark:scrollbar-thumb-slate-700 scrollbar-track-transparent"
        style={{ scrollbarWidth: 'thin' }}
        onMouseEnter={() => autoScrollEnabled && setIsPaused(true)}
        onMouseLeave={() => autoScrollEnabled && setIsPaused(false)}
      >
        <div className="flex gap-6 pb-4" style={{ minWidth: 'max-content' }}>
          {data.templates.map((template, index) => {
            const theme = themeConfigs[index % themeConfigs.length];
            return (
              <div 
                key={index} 
                className={`w-96 rounded-2xl border-2 p-6 hover:transform hover:-translate-y-2 transition-all duration-300 hover:shadow-2xl flex-shrink-0 shadow-lg backdrop-blur-sm ${theme.bg} ${theme.border}`}
              >
                {/* Icon Header */}
                {template.icon && (
                  <div className={`w-14 h-14 rounded-xl ${theme.iconBg} flex items-center justify-center mb-4 shadow-md`}>
                    <i className={`${template.icon} text-2xl ${theme.iconText}`}></i>
                  </div>
                )}

                {/* Title with Gradient */}
                <h3 className={`text-xl font-bold mb-3 bg-gradient-to-r ${theme.gradient} bg-clip-text text-transparent`}>
                  {template.title}
                </h3>

                {/* Description */}
                <p className={`text-sm leading-relaxed mb-4 ${theme.text}`}>
                  {template.description}
                </p>

                {/* Infographic */}
                {template.infographic && template.infographic.type && (
                  <div className="mt-4 pt-4 border-t border-slate-200/50 dark:border-slate-700/50">
                    <InfographicRenderer 
                      infographic={template.infographic}
                    />
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}